/* 2. Bottom Sheet Popup Styles */
.popup-sheet {
  position: fixed;
  bottom: 0;
  left: 50%;
  transform: translate(-50%, 100%);
  width: 100%;
  max-width: 480px;
  background-color: #ffffff;
  border-radius: 24px 24px 0 0;
  z-index: 1010;
  box-shadow: 0 -10px 40px rgba(0, 0, 0, 0.1);
  transition: transform 0.35s cubic-bezier(0.16, 1, 0.3, 1);
  padding-bottom: 20px;
}

.popup-sheet.show {
  transform: translate(-50%, 0);
}

.sheet-handle-bar {
  width: 100%;
  height: 24px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.sheet-handle-bar::after {
  content: '';
  width: 36px;
  height: 4px;
  background-color: #cbd5e1;
  border-radius: 2px;
}

.option-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.option-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 14px 16px;
  border: 1px solid #e2e8f0;
  border-radius: 12px;
  cursor: pointer;
  transition: all 0.2s ease;
}

.option-item.selected {
  border-color: #6366f1;
  background-color: rgba(99, 102, 241, 0.03);
}
